    if (std::strcmp(str, "real") == 0) { out = ISO11404ValueSpace::REAL; return true; }
    if (std::strcmp(str, "scaled") == 0) { out = ISO11404ValueSpace::SCALED; return true; }
    if (std::strcmp(str, "character") == 0) { out = ISO11404ValueSpace::CHARACTER; return true; }
    if (std::strcmp(str, "characterstring") == 0) { out = ISO11404ValueSpace::CHARACTERSTRING; return true; }
    if (std::strcmp(str, "boolean") == 0) { out = ISO11404ValueSpace::BOOLEAN; return true; }
    if (std::strcmp(str, "set") == 0) { out = ISO11404ValueSpace::SET; return true; }
    if (std::strcmp(str, "array") == 0) { out = ISO11404ValueSpace::ARRAY; return true; }
    if (std::strcmp(str, "time") == 0) { out = ISO11404ValueSpace::TIME; return true; }
